import{f as l,D as E,o as s,c as A,a2 as e,b as a,w as o,a as n,G as i,a5 as d}from"./chunks/framework.Ccw_j35p.js";const D=JSON.parse('{"title":"架构分层与扩展总览","description":"","frontmatter":{},"headers":[],"relativePath":"high-concurrency/architecture-scaling/index.md","filePath":"high-concurrency/architecture-scaling/index.md","lastUpdated":1780917900000}'),B={name:"high-concurrency/architecture-scaling/index.md"};function g(u,t,p,h,c,S){const r=E("Mermaid");return s(),A("div",null,[t[2]||(t[2]=e('<h1 id="架构分层与扩展总览" tabindex="-1">架构分层与扩展总览 <a class="header-anchor" href="#架构分层与扩展总览" aria-label="Permalink to &quot;架构分层与扩展总览&quot;">​</a></h1><p>创建日期：2026-06-06</p><h2 id="模块概述" tabindex="-1">模块概述 <a class="header-anchor" href="#模块概述" aria-label="Permalink to &quot;模块概述&quot;">​</a></h2><p>高并发系统不是靠&quot;堆机器&quot;就能解决的，需要合理的架构分层和扩展策略。本模块从负载均衡、服务发现、动静分离、读写分离到多活架构，系统讲解架构扩展的核心技术。</p><div class="tip custom-block"><p class="custom-block-title">核心思想</p><p>架构扩展的本质是：<strong>用水平扩展代替垂直扩展，用无状态设计代替有状态依赖，用异步代替同步，用缓存代替直接访问。</strong></p></div><h2 id="垂直扩展-vs-水平扩展" tabindex="-1">垂直扩展 vs 水平扩展 <a class="header-anchor" href="#垂直扩展-vs-水平扩展" aria-label="Permalink to &quot;垂直扩展 vs 水平扩展&quot;">​</a></h2>',6)),(s(),a(d,null,{default:o(()=>[i(r,{id:"mermaid-20",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20subgraph%20%E5%9E%82%E7%9B%B4%E6%89%A9%E5%B1%95%5B%22%E5%9E%82%E7%9B%B4%E6%89%A9%E5%B1%95%EF%BC%88Scale%20Up%EF%BC%89%22%5D%0A%20%20%20%20%20%20%20%20V1%5B%E5%8D%87%E7%BA%A7CPU%208%E6%A0%B8%E2%86%9264%E6%A0%B8%5D%0A%20%20%20%20%20%20%20%20V2%5B%E5%A2%9E%E5%8A%A0%E5%86%85%E5%AD%98%2016G%E2%86%92256G%5D%0A%20%20%20%20%20%20%20%20V3%5BHDD%E2%86%92SSD%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E6%B0%B4%E5%B9%B3%E6%89%A9%E5%B1%95%5B%22%E6%B0%B4%E5%B9%B3%E6%89%A9%E5%B1%95%EF%BC%88Scale%20Out%EF%BC%89%22%5D%0A%20%20%20%20%20%20%20%20H1%5B%E5%8A%A0%E6%9C%BA%E5%99%A8%201%E5%8F%B0%E2%86%92100%E5%8F%B0%5D%0A%20%20%20%20%20%20%20%20H2%5B%E5%88%86%E5%BA%93%E5%88%86%E8%A1%A8%5D%0A%20%20%20%20%20%20%20%20H3%5B%E5%A4%9A%E6%9C%BA%E6%88%BF%E9%83%A8%E7%BD%B2%5D%0A%20%20%20%20end%0A%0A%20%20%20%20style%20%E5%9E%82%E7%9B%B4%E6%89%A9%E5%B1%95%20fill%3A%23ffebee%2Cstroke%3A%23f44336%0A%20%20%20%20style%20%E6%B0%B4%E5%B9%B3%E6%89%A9%E5%B1%95%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A"})]),fallback:o(()=>[...t[0]||(t[0]=[n(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=e('<table tabindex="0"><thead><tr><th>对比维度</th><th>垂直扩展</th><th>水平扩展</th></tr></thead><tbody><tr><td>实现难度</td><td>简单（换硬件）</td><td>复杂（需要架构改造）</td></tr><tr><td>成本</td><td>后期指数增长</td><td>线性增长</td></tr><tr><td>上限</td><td>有物理上限</td><td>理论上无限</td></tr><tr><td>可用性</td><td>单点故障</td><td>天然高可用</td></tr><tr><td>适用场景</td><td>初期、快速上线</td><td>中长期、高并发</td></tr></tbody></table><h2 id="分层架构全景图" tabindex="-1">分层架构全景图 <a class="header-anchor" href="#分层架构全景图" aria-label="Permalink to &quot;分层架构全景图&quot;">​</a></h2>',2)),(s(),a(d,null,{default:o(()=>[i(r,{id:"mermaid-96",class:"mermaid",graph:"flowchart%20TB%0A%20%20%20%20subgraph%20%E6%8E%A5%E5%85%A5%E5%B1%82%5B%22%E6%8E%A5%E5%85%A5%E5%B1%82%22%5D%0A%20%20%20%20%20%20%20%20DNS%5BDNS%20%E8%A7%A3%E6%9E%90%5D%0A%20%20%20%20%20%20%20%20CDN%5BCDN%20%E5%8A%A0%E9%80%9F%5D%0A%20%20%20%20%20%20%20%20LB%5B%E8%B4%9F%E8%BD%BD%E5%9D%87%E8%A1%A1%20Nginx%2FLVS%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E7%BD%91%E5%85%B3%E5%B1%82%5B%22%E7%BD%91%E5%85%B3%E5%B1%82%22%5D%0A%20%20%20%20%20%20%20%20GW%5BAPI%20%E7%BD%91%E5%85%B3%3Cbr%2F%3E%E9%89%B4%E6%9D%83%2F%E9%99%90%E6%B5%81%2F%E8%B7%AF%E7%94%B1%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E4%B8%9A%E5%8A%A1%E5%B1%82%5B%22%E4%B8%9A%E5%8A%A1%E5%B1%82%EF%BC%88%E6%97%A0%E7%8A%B6%E6%80%81%EF%BC%89%22%5D%0A%20%20%20%20%20%20%20%20S1%5B%E6%9C%8D%E5%8A%A11%5D%0A%20%20%20%20%20%20%20%20S2%5B%E6%9C%8D%E5%8A%A12%5D%0A%20%20%20%20%20%20%20%20S3%5B%E6%9C%8D%E5%8A%A13%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20%E6%95%B0%E6%8D%AE%E5%B1%82%5B%22%E6%95%B0%E6%8D%AE%E5%B1%82%EF%BC%88%E6%9C%89%E7%8A%B6%E6%80%81%EF%BC%89%22%5D%0A%20%20%20%20%20%20%20%20CACHE%5BRedis%20%E7%BC%93%E5%AD%98%E9%9B%86%E7%BE%A4%5D%0A%20%20%20%20%20%20%20%20DB%5B(MySQL%20%E8%AF%BB%E5%86%99%E5%88%86%E7%A6%BB)%5D%0A%20%20%20%20%20%20%20%20MQ%5B%E6%B6%88%E6%81%AF%E9%98%9F%E5%88%97%5D%0A%20%20%20%20%20%20%20%20OSS%5B%E5%AF%B9%E8%B1%A1%E5%AD%98%E5%82%A8%5D%0A%20%20%20%20end%0A%0A%20%20%20%20%E6%8E%A5%E5%85%A5%E5%B1%82%20--%3E%20%E7%BD%91%E5%85%B3%E5%B1%82%20--%3E%20%E4%B8%9A%E5%8A%A1%E5%B1%82%20--%3E%20%E6%95%B0%E6%8D%AE%E5%B1%82%0A%0A%20%20%20%20style%20%E6%8E%A5%E5%85%A5%E5%B1%82%20fill%3A%23ffebee%2Cstroke%3A%23f44336%0A%20%20%20%20style%20%E7%BD%91%E5%85%B3%E5%B1%82%20fill%3A%23e3f2fd%2Cstroke%3A%232196f3%0A%20%20%20%20style%20%E4%B8%9A%E5%8A%A1%E5%B1%82%20fill%3A%23e8f5e9%2Cstroke%3A%234caf50%0A%20%20%20%20style%20%E6%95%B0%E6%8D%AE%E5%B1%82%20fill%3A%23fff3e0%2Cstroke%3A%23ff9800%0A"})]),fallback:o(()=>[...t[1]||(t[1]=[n(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=e('<h2 id="各层瓶颈与解决思路" tabindex="-1">各层瓶颈与解决思路 <a class="header-anchor" href="#各层瓶颈与解决思路" aria-label="Permalink to &quot;各层瓶颈与解决思路&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>典型瓶颈</th><th>解决思路</th></tr></thead><tbody><tr><td><strong>接入层</strong></td><td>DNS 解析慢、单点 Nginx 压力大</td><td>DNS 智能解析、CDN 加速、多 Nginx + 负载均衡</td></tr><tr><td><strong>网关层</strong></td><td>鉴权/限流成为瓶颈</td><td>网关集群 + 本地缓存鉴权信息</td></tr><tr><td><strong>业务层</strong></td><td>单实例 CPU/内存打满</td><td>无状态设计 + 水平扩展</td></tr><tr><td><strong>数据层</strong></td><td>单库连接数耗尽、单表数据量过大</td><td>读写分离、分库分表、缓存</td></tr></tbody></table><h2 id="无状态服务弹性伸缩" tabindex="-1">无状态服务弹性伸缩 <a class="header-anchor" href="#无状态服务弹性伸缩" aria-label="Permalink to &quot;无状态服务弹性伸缩&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">为什么无状态才能水平扩展？</p><p>无状态服务不存储会话数据，请求可以打到任意实例。有状态服务（如持有 Session 的 Web 应用）需要会话保持（Sticky Session），限制了负载均衡的灵活性，且扩容时需要迁移状态。</p></div><p><strong>无状态化改造：</strong></p><ul><li>Session 外置到 Redis。</li><li>文件存储外置到 OSS。</li><li>配置外置到配置中心。</li></ul><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><ol><li><strong>负载均衡</strong>：理解流量如何分发到多个实例，各算法优缺点。</li><li><strong>服务发现</strong>：理解服务实例如何注册和发现，不同 CAP 选择。</li><li><strong>动静分离+读写分离</strong>：理解如何分流不同类型的请求。</li><li><strong>多活架构+链路追踪</strong>：理解跨机房容灾和全链路监控。</li></ol><hr><h2 id="经典高频面试题" tabindex="-1">经典高频面试题 <a class="header-anchor" href="#经典高频面试题" aria-label="Permalink to &quot;经典高频面试题&quot;">​</a></h2><h3 id="q1-垂直扩展和水平扩展有什么区别-什么时候选哪个" tabindex="-1">Q1：垂直扩展和水平扩展有什么区别？什么时候选哪个？ <a class="header-anchor" href="#q1-垂直扩展和水平扩展有什么区别-什么时候选哪个" aria-label="Permalink to &quot;Q1：垂直扩展和水平扩展有什么区别？什么时候选哪个？&quot;">​</a></h3><p><strong>知识要点：</strong> 垂直扩展=升级单机硬件（Scale Up），有物理上限；水平扩展=增加机器数量（Scale Out），理论上无限。</p><p><strong>我们一个创业项目在早期犯过&quot;过早水平扩展&quot;的错误。</strong> 当时日活只有5000，但团队看了很多微服务文章，一口气拆了8个微服务，部署在16台虚拟机上。结果每月云成本3万多，而实际QPS峰值才200。后来做了一次&quot;反向合并&quot;——把这8个服务合并回2个单体，部署在2台4核8G的机器上，应用启动时间从45秒降到8秒，没人抱怨性能。</p><p><strong>踩坑经历：</strong> 另一个极端案例是我们另一个项目已经到了瓶颈还在坚持垂直扩展。一路从4核升到16核，成本翻了4倍但吞吐量只涨了60%（因为JVM GC在16核上的Stop-The-World时间反而更长了）。最终6台4核做水平扩展，总吞吐量是1台16核的2.8倍，但成本只多了50%。我们的经验法则是：单机扩容成本超过水平扩容成本的1.5倍时，坚决转水平扩展。</p><p><strong>量化结果：</strong> 反向合并后月度云成本从3.2万降到4200（降低87%），部署时间从12分钟降到2分钟。水平扩展案例中，6台4核支撑QPS 3800 vs 1台16核的1350，性价比提升约2.5倍。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;水平扩展最大的技术挑战是什么？&quot; —— 状态管理。无状态服务水平扩展很容易（加机器+改Nginx upstream），有状态服务才是难点——数据库分库分表、缓存数据再平衡、Session共享。我们一般先做无状态化改造（Session外置Redis、文件存OSS），再做水平扩展。</li><li><strong>追问2：</strong> &quot;什么时候水平扩展也不管用了？&quot; —— 两种场景：一是数据库写入瓶颈（所有请求最终都要写DB），水平扩展应用层不解决DB问题，需要分库分表或引入MQ削峰；二是中心化资源争用（如全局唯一ID生成器），水平扩展会加剧锁竞争。</li></ul><h3 id="q2-为什么无状态服务才能水平扩展-有状态怎么处理" tabindex="-1">Q2：为什么无状态服务才能水平扩展？有状态怎么处理？ <a class="header-anchor" href="#q2-为什么无状态服务才能水平扩展-有状态怎么处理" aria-label="Permalink to &quot;Q2：为什么无状态服务才能水平扩展？有状态怎么处理？&quot;">​</a></h3><p><strong>知识要点：</strong> 无状态=请求可打到任意实例、扩容缩容自由；有状态需要将状态外置。</p><p><strong>我们在把一个老系统从单机迁移到集群时，被Session坑得刻骨铭心。</strong> 运维加了3台机器上线，用户开始投诉&quot;登录后莫名其妙被踢出来&quot;——因为第一次登录在机器A上创建了Session，第二次请求被Nginx轮询到机器B，B没有这个Session，返回了401。运维紧急改Nginx为ip_hash（同一IP打同一机器），虽然暂时能用了，但公司的NAT网关导致所有人的请求都打到同一台机器，其它3台完全浪费。</p><p><strong>踩坑经历：</strong> 真正解决方案是Session外置到Redis（Spring Session），整个过程改造成本较低但有一处遗漏——有个老模块用了<code>HttpSession.setAttribute</code>存购物车数据（每个用户的购物车对象大约5KB），迁移到Redis后Redis内存一周飙了2GB。原来是因为购物车数据本来只在内存中，现在所有用户的全量购物车都进了Redis。修复方案是购物车数据改用数据库+缓存（按需加载），Redis只存Session ID→用户ID的映射（每条约200字节）。</p><p><strong>量化结果：</strong> Redis化Session后，集群利用率从25%提升到78%（四台均衡）。Redis内存从2GB优化到180MB（只保存Session映射）。用户登录被踢的投诉从每天15次降到0次。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;Sticky Session（ip_hash）不是也能解决吗？为什么一定要外置？&quot; —— Sticky Session有四个致命缺陷：一是负载不均（我们NAT网关下所有人一个IP），二是机器下线Session全丢，三是灰度发布困难（新版本机器需要重新登录），四是故障转移做不到（A机器挂了不能切到B）。外置Session彻底解决这四个问题。</li><li><strong>追问2：</strong> &quot;文件存储怎么外置？原来的<code>File f = new File(&#39;/data/upload/&#39;)</code>怎么改？&quot; —— 我们封装了一个<code>StorageService</code>接口，有两个实现：本地文件系统和OSS。老系统先切到接口（不改逻辑），然后替换实现为OSS。最大的坑是URL生成——本地文件返回<code>/static/xxx.jpg</code>，OSS返回<code>https://oss-cdn.com/xxx.jpg</code>，前端模板里的硬编码URL全要改。所以我们强烈建议一开始就用对象存储。</li></ul><h3 id="q3-分层架构设计有什么好处" tabindex="-1">Q3：分层架构设计有什么好处？ <a class="header-anchor" href="#q3-分层架构设计有什么好处" aria-label="Permalink to &quot;Q3：分层架构设计有什么好处？&quot;">​</a></h3><p><strong>知识要点：</strong> 关注点分离、独立扩展、故障隔离、统一安全管控。</p><p><strong>我们曾经因为网关层故障把整个业务全拖垮了。</strong> 初期架构里网关和业务服务部署在同一组机器上（为了省成本），一次网关的限流配置错误（把全局限流设成了每秒10次），所有机器上的网关都触发限流，业务请求全军覆没。如果网关是独立层部署，限流配错了只影响网关层，业务服务还能通过直接IP访问临时补救。</p><p><strong>踩坑经历：</strong> 整改后严格按四层架构拆分：接入层（Nginx+LVS）→ 网关层（独立部署Kong集群）→ 业务层（微服务）→ 数据层（DB/Redis/MQ）。每个层独立部署、独立监控、独立容量规划。有一次网关层CPU告警，排查发现是一个新上的频率限制插件有问题，但由于隔离充分，业务层完全没受影响，用户无感知地修了bug。</p><p><strong>量化结果：</strong> 分层改造后，故障影响范围缩小了约80%——过去一次问题影响全链路，现在90%的故障只影响单一层。单次故障平均恢复时间从45分钟降到18分钟。每层独立扩容的响应时间从3天（整体扩容需要协调）降到半天。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;四层架构增加了一跳延迟，性能损失多少？&quot; —— 每多一跳增加约0.5-2ms（内网延迟），四层总共多了三跳（接入→网关→业务→数据），累计约3-5ms。相比业务逻辑本身的处理时间（通常50-200ms），这个开销不到5%，完全值得。</li><li><strong>追问2：</strong> &quot;如果数据层挂了，上层怎么办？&quot; —— 降级是分层架构的标准配套。数据层不可用时，业务层要能降级：Redis挂了走数据库、数据库挂了走本地缓存、数据库主库挂了走从库只读模式。我们测试过&quot;数据层全挂&quot;的极端场景，业务层能在2秒内切换到静态兜底页。</li></ul><h3 id="q4-如何定位系统瓶颈在哪一层" tabindex="-1">Q4：如何定位系统瓶颈在哪一层？ <a class="header-anchor" href="#q4-如何定位系统瓶颈在哪一层" aria-label="Permalink to &quot;Q4：如何定位系统瓶颈在哪一层？&quot;">​</a></h3><p><strong>知识要点：</strong> 接入层看Nginx连接数，网关层看鉴权/路由延迟，业务层看CPU/GC/线程池，数据层看连接数和慢查询。</p><p><strong>我们有次大促前做了全链路压测，用这个方法精准定位了瓶颈。</strong> 压测从1000 QPS开始逐步加，到3200 QPS时P99延迟突然从120ms跳到800ms。按照排查流程：先看Nginx（连接数3000，远没到上限）→ 再看网关（CPU 25%，正常）→ 看业务服务（CPU 35%，正常）→ 看Redis（CPU 12%，正常）→ 看MySQL：连接数28（max 200，正常），但慢查询日志里突然出现大量<code>Sending data</code>状态，原来是一个TOP 10商品查询没走索引。</p><p><strong>踩坑经历：</strong> 最容易被忽视的一层是网络层。我们遇到过P99延迟突然飙升到3秒，查了所有应用层的指标都没问题，最后通过<code>tcpdump</code>抓包发现是云服务商的一个网络设备丢包率到了8%。没有网络层的监控（ping延迟/丢包率），这个问题根本没法定位。后来我们在每一层都加了网络质量监控（各层机器之间互Ping，记录延迟和丢包）。</p><p><strong>量化结果：</strong> 建立了分层瓶颈定位SOP后，故障定位时间从平均2.5小时降到30分钟。大促前的三轮压测中每次都精准找到了瓶颈点并提前解决，大促当天零故障。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;如果我只有Grafana一个Dashboard，怎么快速判断瓶颈在哪层？&quot; —— 先看一个&quot;四宫格&quot;：Nginx QPS是否接近上限、业务服务GC频率是否异常、Redis命中率是否暴跌、MySQL慢查询数是否突增。这四个指标通常能覆盖90%的瓶颈场景。任何一个异常就去该层深入分析。</li><li><strong>追问2：</strong> &quot;GC频繁导致的性能下降，属于哪一层？&quot; —— 属于业务层。判断方法是看GC日志中Full GC的频率和耗时。我们线上有个服务Full GC从每2小时一次突然变成每3分钟一次（每次STW 800ms），GC期间所有请求超时。定位是代码里一个缓存Map忘记设容量上限，慢慢地膨胀到2GB+。</li></ul><h3 id="q5-什么时候该做读写分离" tabindex="-1">Q5：什么时候该做读写分离？ <a class="header-anchor" href="#q5-什么时候该做读写分离" aria-label="Permalink to &quot;Q5：什么时候该做读写分离？&quot;">​</a></h3><p><strong>知识要点：</strong> 读远大于写（如10:1以上）、单库连接数接近上限、业务可接受主从延迟。</p><p><strong>我们做读写分离的契机是数据库连接数打满了。</strong> 促销活动期间，监控显示MySQL连接数频繁触达180/200（max_connections=200），大量请求报<code>Too many connections</code>。分析发现80%是读请求，只有20%是写。加了一个只读从库后，读流量分流到从库，主库连接数从180降到50，再也没超限过。</p><p><strong>踩坑经历：</strong> 但不是所有项目都该做读写分离。我们一个SaaS管理后台跟风做了，主从两台机器月成本1200，但监控显示从库每天平均2个连接（因为大部分读走了缓存层），相当于花600块养了一个闲置的从库。所以后来我们有了&quot;读写分离前先看缓存命中率&quot;的规定——Redis命中率&gt;95%的接口不做读写分离，缓存已经解决了读压力。</p><p><strong>量化结果：</strong> 促销系统加从库后，<code>Too many connections</code>告警从每天3次降到0次，主库CPU从78%降到42%。但那个SaaS后台撤了从库后，Redis命中率从95%涨到97%（因为读请求部分回流Redis做了预热），成本降了600/月，延迟没任何变化。</p><p><strong>面试官追问：</strong></p><ul><li><strong>追问1：</strong> &quot;一主多从和主主复制，有什么区别和选型？&quot; —— 一主多从是最常见模式（单点写入多读分摊），简单稳定。主主复制（双写）极其危险——两个主同时写入同一行数据会直接冲突，自增ID也会冲突。除非有非常完善的冲突解决机制（如Global Transaction ID），否则绝对不要用主主复制。我们唯一用过的一次是数据库迁移，双写3天后就切掉了。</li><li><strong>追问2：</strong> &quot;读写分离配合分库分表，有没有什么坑？&quot; —— 最大的坑在ShardingSphere的事务管理。跨分片的分布式事务已经够复杂了，再加上读写分离（每个分片还有主从），出问题时很难定位是哪个分片的哪个库出了问题。我们的做法是读写分离尽量在同一分片内完成，避免跨分片+跨主从的超级复杂路径。</li></ul>',45))])}const b=l(B,[["render",g]]);export{D as __pageData,b as default};
